__kernel void lud_diagonal(__global float* a, __local float* temp, const int size, const int offset)
{
    int i = get_global_id(0);
    int j, k;
    float temp_val;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory if needed, or operate directly
    // The original OMP code operates directly on 'a'. 
    // We will follow the logic:
    // for i = 0 to BS
    //   for j = i to BS: A(i,j) -= sum(A(i,k)*A(k,j))
    //   temp = 1/A(i,i)
    //   for j = i+1 to BS: A(j,i) -= sum(...); A(j,i) *= temp

    // Since this is a sequential dependency within the block, we must execute sequentially or use synchronization.
    // Given the small size (16), we can just run the loop sequentially in one thread or synchronize.
    // The original OMP code runs this sequentially in one thread context effectively (no parallelism inside lud_diagonal_omp).
    // So we run the whole block in one thread (global_id 0) or replicate logic. 
    // To match the original structure where one thread does the work:
    if (i == 0) {
        for (int row = 0; row < BLOCK_SIZE; row++) {
            // Update upper triangle (including diagonal)
            for (int col = row; col < BLOCK_SIZE; col++) {
                float sum = 0.0f;
                for (k = 0; k < row; k++) {
                    sum += a[(offset + row) * size + (offset + k)] * a[(offset + k) * size + (offset + col)];
                }
                a[(offset + row) * size + (offset + col)] -= sum;
            }

            temp_val = 1.0f / a[(offset + row) * size + (offset + row)];

            // Update lower triangle
            for (int col = row + 1; col < BLOCK_SIZE; col++) {
                float sum = 0.0f;
                for (k = 0; k < row; k++) {
                    sum += a[(offset + col) * size + (offset + k)] * a[(offset + k) * size + (offset + row)];
                }
                a[(offset + col) * size + (offset + row)] = (a[(offset + col) * size + (offset + row)] - sum) * temp_val;
            }
        }
    }
}

